mapper.insert:
MERGE INTO UIDBS01.NF_SCRN_INFO_MGT X
USING (
	SELECT 
		COUNT(*) COUNT
	FROM
		UIDBS01.NF_SCRN_INFO_MGT
	WHERE
		BIZ_TYPE = #{bizType}
		AND CUST_NO = #{custNo}
		AND TRAD_NO = #{tradNo}
) Y
ON (
	Y.COUNT > 0
	AND X.CUST_NO = #{custNo}
	AND X.TRAD_NO = #{tradNo}
)
WHEN MATCHED THEN
	UPDATE 
	SET
		X.SCRN_DATA_INFO = #{scrnDataInfo, jdbcType=CLOB}
WHEN NOT MATCHED THEN
	INSERT (
		X.BIZ_TYPE,
		X.CUST_NO,
		X.TRAD_NO,
		X.SCRN_DATA_INFO
	) VALUES (
		#{bizType},
		#{custNo},
		#{tradNo},
		#{scrnDataInfo, jdbcType=CLOB}
	)
